// No Controller — dispara o evento
public function store(StoreCadastroRequest $request)
{
    $user = User::create($request->validated());

    // Disparar evento — todos os Listeners são notificados
    UsuarioCadastrado::dispatch($user);
    // Ou: event(new UsuarioCadastrado($user));

    return redirect()->route('dashboard');
}
